kernel_src="""

#include "kernel_operator.h"

constexpr int32_t BUFFER_NUM = 2;

class KernelMaskedCumsumCustom {
public:
    __aicore__ inline KernelMaskedCumsumCustom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR mask, GM_ADDR y,
                                uint32_t totalLength, uint32_t seqLen,
                                uint32_t tileLen, uint32_t blockDim)
    {
        totalLen_ = totalLength;
        seqLen_ = seqLen;
        tileLen_ = tileLen;
        blockDim_ = blockDim;

        xGm_.SetGlobalBuffer((__gm__ float*)x, totalLen_);
        maskGm_.SetGlobalBuffer((__gm__ uint8_t*)mask, totalLen_);
        yGm_.SetGlobalBuffer((__gm__ float*)y, totalLen_);

        pipe_.InitBuffer(inQueueX_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(inQueueMask_, BUFFER_NUM, tileLen_ * sizeof(uint8_t));
        pipe_.InitBuffer(outQueueY_, BUFFER_NUM, tileLen_ * sizeof(float));
    }

    __aicore__ inline void Process()
    {
        if (totalLen_ == 0 || seqLen_ == 0 || tileLen_ == 0) return;

        uint32_t numSeqs = totalLen_ / seqLen_;
        uint32_t blockIdx = AscendC::GetBlockIdx();
        for (uint32_t seq = blockIdx; seq < numSeqs; seq += blockDim_)
        {
            uint32_t base = seq * seqLen_;
            uint32_t remaining = seqLen_;
            float carry = 0.0f;
            uint32_t offset = 0;
            while (remaining > 0)
            {
                uint32_t curTile = (remaining < tileLen_) ? remaining : tileLen_;

                AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
                AscendC::DataCopy(xLocal, xGm_[base + offset], curTile);
                inQueueX_.EnQue(xLocal);

                AscendC::LocalTensor<uint8_t> maskLocal = inQueueMask_.AllocTensor<uint8_t>();
                AscendC::DataCopy(maskLocal, maskGm_[base + offset], curTile);
                inQueueMask_.EnQue(maskLocal);

                AscendC::LocalTensor<float> xTile = inQueueX_.DeQue<float>();
                AscendC::LocalTensor<uint8_t> maskBool = inQueueMask_.DeQue<uint8_t>();

                AscendC::LocalTensor<float> yTile = outQueueY_.AllocTensor<float>();

                for (uint32_t i = 0; i < curTile; i++)
                {
                    float val = xTile.GetValue(i);
                    uint8_t m = maskBool.GetValue(i);
                    if (m != 0)
                    {
                        carry += val;
                    }
                    yTile.SetValue(i, carry);
                }

                inQueueX_.FreeTensor(xTile);
                inQueueMask_.FreeTensor(maskBool);
                outQueueY_.EnQue<float>(yTile);

                AscendC::LocalTensor<float> yOut = outQueueY_.DeQue<float>();
                AscendC::DataCopy(yGm_[base + offset], yOut, curTile);
                outQueueY_.FreeTensor(yOut);

                remaining -= curTile;
                offset += curTile;
            }
        }
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueueX_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueueMask_;
    AscendC::TQue<AscendC::TPosition::VECOUT, BUFFER_NUM> outQueueY_;

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<uint8_t> maskGm_;
    AscendC::GlobalTensor<float> yGm_;

    uint32_t totalLen_;
    uint32_t seqLen_;
    uint32_t tileLen_;
    uint32_t blockDim_;
};

extern "C" __global__ __aicore__ void masked_cumsum_custom(GM_ADDR x, GM_ADDR mask, GM_ADDR y, GM_ADDR workspace, GM_ADDR tiling)
{
    GET_TILING_DATA(tiling_data, tiling);
    KernelMaskedCumsumCustom op;
    op.Init(x, mask, y, tiling_data.totalLength, tiling_data.seqLen, tiling_data.tileLen, tiling_data.blockDim);
    op.Process();
}
